pragma cashscript ^0.12.0;

// =============================================================================
// XMR-BCH Atomic Swap using Adaptor Signatures
// =============================================================================
//
// Unlike hash-based cross-chain swaps (HTLCs), Monero does not support scripts 
// and cannot verify SHA-256 hashes on the blockchain. Therefore, we use Point 
// Time-Locked Contracts (PTLCs) via Adaptor Signatures.
//
// The magic happens *off-chain* during the SDK handshake. By providing a valid
// ECDSA/Schnorr signature to claim the BCH, the recipient mathematically reveals 
// the scalar (the secret) needed to unlock the Monero 2-of-2 multisig wallet.
//
// To the Bitcoin Cash blockchain, this just looks like a simple identity check.

contract XmrAdaptorSwap(
    // The public key hash of the recipient (who claims the funds and reveals the secret)
    bytes20 recipientPkh,
    // The public key hash of the sender (who locks the funds & can refund if swap fails)
    bytes20 senderPkh,
    // Unix timestamp when the swap expires and the sender can reclaim their BCH
    int timelock
) {
    // =========================================================================
    // claim() — Recipient claims by providing a valid transaction signature
    // =========================================================================
    function claim(pubkey recipientPk, sig recipientSig) {
        // Enforce identity: Only the intended recipient can claim
        require(hash160(recipientPk) == recipientPkh);
        
        // Enforce signature: The signature itself acts as the secret reveal
        // for the Adaptor protocol. The relayer extracts the `sig` bytes.
        require(checkSig(recipientSig, recipientPk));
    }

    // =========================================================================
    // refund() — Sender reclaims funds after the timelock expires
    // =========================================================================
    function refund(pubkey senderPk, sig senderSig) {
        // Enforce identity: Only the original sender can refund
        require(hash160(senderPk) == senderPkh);
        
        // Enforce signature: Standard spend authorization
        require(checkSig(senderSig, senderPk));
        
        // Enforce time: The locktime must have expired
        require(tx.time >= timelock);
    }
}
